def nstrip(s):
    return re.sub(r'\s+', ' ', norm_ar(s)).strip()

def lcs_len(a, b):
    # compute LCS length char-level for normalized strings
    a = nstrip(a)
    b = nstrip(b)
    # dynamic programming O(n*m) might be heavy but small strings
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[m], a, b

def lcs_ratio(a, b):
    l, na, nb = lcs_len(a, b)
    return l/ max(len(na), len(nb))

