def search_hadith(query, fields=('hadithTxt','Matn')):
    nquery = norm_ar(query)
    results = []
    for rec in hadith_db:
        for field in fields:
            text = rec.get(field)
            if not text:
                continue
            if nquery in norm_ar(text):
                results.append((rec, field))
                break
    return results

